mapper.update:
UPDATE knowledge_graph_runs
SET status = 'RUNNING',
    total_chunk_count = #{totalChunkCount},
    started_at = #{startedAt},
    updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE knowledge_graph_runs
SET processed_chunk_count = #{processedChunkCount},
    skipped_chunk_count = #{skippedChunkCount},
    failed_chunk_count = #{failedChunkCount},
    updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE knowledge_graph_runs
SET status = 'FAILED',
    error_message = #{errorMessage},
    completed_at = #{completedAt},
    updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE knowledge_graph_runs
SET status = 'CANCELLED',
    completed_at = #{completedAt},
    updated_at = #{updatedAt}
WHERE id = #{id}

mapper.insert:
INSERT INTO knowledge_graph_nodes (
    id, scope_type, scope_id, canonical_name, display_name, node_type,
    description, confidence, mention_count, created_at, updated_at
)
VALUES (
    #{id}, #{scopeType}, #{scopeId}, #{canonicalName}, #{displayName}, #{nodeType},
    #{description}, #{confidence}, #{mentionCount}, #{createdAt}, #{updatedAt}
)

INSERT INTO knowledge_graph_edges (
    id, scope_type, scope_id, source_node_id, target_node_id, relation_type,
    display_label, description, confidence, mention_count, created_at, updated_at
)
VALUES (
    #{id}, #{scopeType}, #{scopeId}, #{sourceNodeId}, #{targetNodeId}, #{relationType},
    #{displayLabel}, #{description}, #{confidence}, #{mentionCount}, #{createdAt}, #{updatedAt}
)

INSERT INTO knowledge_graph_evidence (
    id, run_id, node_id, edge_id, document_id, chunk_id, quote, confidence, created_at
)
VALUES (
    #{id}, #{runId}, #{nodeId}, #{edgeId}, #{documentId}, #{chunkId}, #{quote}, #{confidence}, #{createdAt}
)

INSERT INTO knowledge_graph_views (
    id, scope_type, scope_id, view_type, payload_json, generated_from_run_id, created_at, updated_at
)
VALUES (
    #{id}, #{scopeType}, #{scopeId}, #{viewType}, #{payloadJson}, #{generatedFromRunId}, #{createdAt}, #{updatedAt}
)

